import{_ as e,o as r,c as l,ak as i}from"./chunks/framework.B_unCYUt.js";const b=JSON.parse('{"title":"Java程序设计语言","description":"","frontmatter":{},"headers":[],"relativePath":"Courses/Java程序设计语言.md","filePath":"Courses/Java程序设计语言.md","lastUpdated":1708868588000}'),o={name:"Courses/Java程序设计语言.md"};function t(n,a,s,h,d,c){return r(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="java程序设计语言" tabindex="-1">Java程序设计语言 <a class="header-anchor" href="#java程序设计语言" aria-label="Permalink to “Java程序设计语言”">​</a></h1><h1 id="java概述" tabindex="-1">Java概述 <a class="header-anchor" href="#java概述" aria-label="Permalink to “Java概述”">​</a></h1><p>既是开发环境, 又是应用环境</p><h2 id="常见缩写" tabindex="-1">常见缩写 <a class="header-anchor" href="#常见缩写" aria-label="Permalink to “常见缩写”">​</a></h2><ul><li>Java标准版(Java 2 Platform, Standard Edition, J2SE) <ul><li>Java企业版(Java 2 Platform, Enterprise Edition, J2EE)</li><li>Java移动版(Java 2 Platform, Micro Edition, J2ME)</li></ul></li></ul><h2 id="java语言特性" tabindex="-1">Java语言特性 <a class="header-anchor" href="#java语言特性" aria-label="Permalink to “Java语言特性”">​</a></h2><p>简单的<strong>面向对象</strong>语言, 并具有<strong>分布性</strong>、<strong>安全性</strong>和<strong>健壮性</strong>。支持<strong>解释和编译执行</strong>两种运行方式; 它是<strong>多线程</strong>的, <strong>动态的语言</strong>; 具有<strong>与平台无关</strong>的特性, 解决软件移植问题。</p><ol><li>语法简单, 功能强大, 安全可靠;</li><li>与平台无关;</li><li>解释编译两种运行方式;</li><li>多线程;</li><li>动态执行兼有丰富的API文档及类库.</li></ol><h2 id="应用场景" tabindex="-1">应用场景 <a class="header-anchor" href="#应用场景" aria-label="Permalink to “应用场景”">​</a></h2><h1 id="基本概念" tabindex="-1">基本概念 <a class="header-anchor" href="#基本概念" aria-label="Permalink to “基本概念”">​</a></h1><h1 id="基础语义" tabindex="-1">基础语义 <a class="header-anchor" href="#基础语义" aria-label="Permalink to “基础语义”">​</a></h1><blockquote><p>语法, 语义, 字面量含义</p></blockquote><h2 id="语言参考" tabindex="-1">语言参考 <a class="header-anchor" href="#语言参考" aria-label="Permalink to “语言参考”">​</a></h2><blockquote><p>只展现不同的部分</p></blockquote><h2 id="语法规则" tabindex="-1">语法规则 <a class="header-anchor" href="#语法规则" aria-label="Permalink to “语法规则”">​</a></h2><ul><li>Java程序由类(class)构成(<em>这不同于python/JavaScript的既支持类也支持函数, Java程序的基本结构是类</em>), 含有一个<code>main()</code>方法 , 称为主方法或主函数. 整个程序的运行入口是main()方法, 该方法执行完毕, 整个程序也即结束.</li><li>一个文件中只能有一个公有类(public class), 类的名字即是该文件的名字(公用类名与文件名必须完全一致).</li><li>Java源代码(程序)文件的扩展名是 <code>.java</code>, 编译后生成的字节码文件的扩展名是 <code>.class</code>, 需要由JVM载入并解释执行. <ul><li>源文件是文本格式文件, 类文件是二进制格式文件, 任何平台编译完成的类文件都具有统一的格式</li></ul></li><li>一个程序可以包含一个或多个<code>.java</code>文件. 无论多少个文件, 都只能有一个<code>main()</code>方法.</li><li>Java程序编写好后, 如果要在计算机上运行, 必须经过<strong>编译</strong>和<strong>解释执行</strong>两个阶段. <ul><li>如果程序由多个文件组成, 需要分别编译各个文件, 得到类文件. 编译出现错误时, 需要重新编译, 直到正确为止.</li></ul></li></ul><h1 id="底层原理" tabindex="-1">底层原理 <a class="header-anchor" href="#底层原理" aria-label="Permalink to “底层原理”">​</a></h1><h1 id="重要专题" tabindex="-1">重要专题 <a class="header-anchor" href="#重要专题" aria-label="Permalink to “重要专题”">​</a></h1><h2 id="面向对象技术" tabindex="-1">面向对象技术 <a class="header-anchor" href="#面向对象技术" aria-label="Permalink to “面向对象技术”">​</a></h2><p>面向过程设计的问题是, 众多的变量名和函数名互不约束, 令程序员不堪重负.</p><p><strong>面向对象方法论</strong>: 使分析, 设计和实现一个系统的方法尽可能地接近人们认识一个系统的方法。</p><h3 id="基本概念-1" tabindex="-1">基本概念 <a class="header-anchor" href="#基本概念-1" aria-label="Permalink to “基本概念”">​</a></h3><p>抽象</p><p>对象</p><p>类</p><p>类型层次(子类)</p><p>封装</p><p>继承性</p><p>多态性</p><h3 id="说明简介" tabindex="-1">说明简介 <a class="header-anchor" href="#说明简介" aria-label="Permalink to “说明简介”">​</a></h3><p>Java程序员只有一种基本的结构, 即类。</p>',31)])])}const v=e(o,[["render",t]]);export{b as __pageData,v as default};
